162→    private static void trackGutenbergEnabledForNonGutenbergSites(final SiteStore siteStore,
163→                                                                  final BlockEditorEnabledSource source) {
164→        for (SiteModel site : siteStore.getSites()) {
165→            if (!TextUtils.equals(site.getMobileEditor(), GB_EDITOR_NAME)) {
166→                AnalyticsUtils.trackWithSiteDetails(Stat.EDITOR_GUTENBERG_ENABLED, site, source.asPropertyMap());
167→            }
168→        }
169→    }
170→
171→    private static boolean atLeastOneSiteHasAztecEnabled(final SiteStore siteStore) {
172→        // We want to make sure to enable Gutenberg only on the sites they didn't opt-out.
173→        for (SiteModel site : siteStore.getSites()) {
174→            if (TextUtils.equals(site.getMobileEditor(), AZTEC_EDITOR_NAME)) {
175→                return true;
176→            }
177→        }
178→        return false;
179→    }
