193→    public static void enableBlockEditor(Dispatcher dispatcher, SiteModel siteModel) {
194→        dispatcher.dispatch(SiteActionBuilder.newDesignateMobileEditorAction(
195→                new DesignateMobileEditorPayload(siteModel, GB_EDITOR_NAME)));
196→    }
