203→    public static boolean isBlockEditorDefaultForNewPost(@Nullable SiteModel site) {
204→        if (site == null) {
205→            return true;
206→        }
207→        if (TextUtils.isEmpty(site.getMobileEditor())) {
208→            // Default to block editor when mobile editor setting is empty
209→            return true;
210→        } else {
211→            return alwaysDefaultToGutenberg(site) || site.getMobileEditor().equals(SiteUtils.GB_EDITOR_NAME);
212→        }
213→    }
