219→    public static String getSiteNameOrHomeURL(SiteModel site) {
220→        String siteName = site.getName();
221→        if (siteName == null) {
222→            return "";
223→        }
224→        if (siteName.trim().length() == 0) {
225→            siteName = getHomeURLOrHostName(site);
226→        }
227→        return siteName;
228→    }
