239→    /**
240→     * @return true if the site is WPCom or Jetpack and is not private
241→     */
242→    public static boolean isPhotonCapable(SiteModel site) {
243→        return SiteUtils.isAccessedViaWPComRest(site) && (!site.isPrivate() || site.isWPComAtomic());
244→    }
