285→    public static SiteAccessibilityInfo getAccessibilityInfoFromSite(@NonNull SiteModel site) {
286→        SiteVisibility siteVisibility;
287→
288→        if (site.isPrivateWPComAtomic()) {
289→            siteVisibility = SiteVisibility.PRIVATE_ATOMIC;
290→        } else if (site.isPrivate()) {
291→            siteVisibility = SiteVisibility.PRIVATE;
292→        } else {
293→            siteVisibility = SiteVisibility.PUBLIC;
294→        }
295→
296→        return new SiteAccessibilityInfo(siteVisibility, isPhotonCapable(site));
297→    }
