299→    public static ArrayList<Integer> getCurrentSiteIds(SiteStore siteStore, boolean selfhostedOnly) {
300→        ArrayList<Integer> siteIDs = new ArrayList<>();
301→        List<SiteModel> sites = selfhostedOnly ? siteStore.getSitesAccessedViaXMLRPC() : siteStore.getSites();
302→        for (SiteModel site : sites) {
303→            siteIDs.add(site.getId());
304→        }
305→
306→        return siteIDs;
307→    }
